import java.util.Scanner;
import java.util.Arrays;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        // Define a maximum buffer size to prevent overflow
        int maxBufferSize = 10;

        System.out.print("Enter a string (up to " + maxBufferSize + " characters): ");
        String userInput = scanner.nextLine();

        // Ensure user input does not exceed the maximum buffer size
        if (userInput.length() > maxBufferSize) {
            System.out.println("Input exceeds maximum buffer size. Please try again.");
            scanner.close();
            return;
        }

        // Use Arrays.copyOf to safely copy user input into a fixed-size buffer
        byte[] buffer = Arrays.copyOf(userInput.getBytes(), maxBufferSize);

        // Print out the contents of the buffer
        System.out.println("Buffer content: " + new String(buffer));

        scanner.close();
    }
}

